import {
  airtableCreate,
  airtableGet,
  type AirtableRecord,
} from "./airtable-client";

export const ACTIVITY_EVENTS_TABLE = "ActivityEvents";

export type ActivityModule =
  | "simplifi"
  | "connect"
  | "update-hub"
  | "training"
  | "portal"
  | "pulse"
  | "system"
  | (string & {});

export interface ActivityEventInput {
  organizationId: string;
  module: ActivityModule;
  eventType: string;
  title: string;
  summary: string;
  priority?: number;
  metric?: string;
  actionLabel?: string;
  actionUrl?: string;
  personId?: string;
  createdAt?: string;
  metadata?: Record<string, unknown>;
}

export interface ActivityEvent extends Required<Pick<ActivityEventInput, "organizationId" | "module" | "eventType" | "title" | "summary">> {
  id: string;
  priority: number;
  metric?: string;
  actionLabel?: string;
  actionUrl?: string;
  personId?: string;
  createdAt: string;
  metadata: Record<string, unknown>;
}

export interface ActivityEventListOptions {
  organizationId?: string;
  module?: ActivityModule;
  maxRecords?: number;
}

export function normalizeActivityEvent(input: ActivityEventInput, id = ""): ActivityEvent {
  return {
    id,
    organizationId: input.organizationId,
    module: input.module,
    eventType: input.eventType,
    title: input.title,
    summary: input.summary,
    priority: clampScore(input.priority ?? 0),
    metric: input.metric,
    actionLabel: input.actionLabel,
    actionUrl: input.actionUrl,
    personId: input.personId,
    createdAt: input.createdAt ?? new Date().toISOString(),
    metadata: input.metadata ?? {},
  };
}

export async function publishActivityEvent(
  baseId: string,
  tableId = ACTIVITY_EVENTS_TABLE,
  input: ActivityEventInput
): Promise<ActivityEvent> {
  const event = normalizeActivityEvent(input);
  const record = await airtableCreate(baseId, tableId, toAirtableFields(event));
  return fromAirtableRecord(record);
}

export async function listActivityEvents(
  baseId: string,
  tableId = ACTIVITY_EVENTS_TABLE,
  options: ActivityEventListOptions = {}
): Promise<ActivityEvent[]> {
  const filters = [
    options.organizationId ? `{organizationId} = '${escapeFormulaValue(options.organizationId)}'` : "",
    options.module ? `{module} = '${escapeFormulaValue(options.module)}'` : "",
  ].filter(Boolean);

  const records = await airtableGet(baseId, tableId, {
    filterByFormula: filters.length === 1 ? filters[0] : filters.length > 1 ? `AND(${filters.join(", ")})` : undefined,
    maxRecords: options.maxRecords ?? 100,
    sort: [{ field: "createdAt", direction: "desc" }],
  });

  return records.map(fromAirtableRecord);
}

export function fromAirtableRecord(record: AirtableRecord): ActivityEvent {
  const fields = record.fields;

  return normalizeActivityEvent(
    {
      organizationId: readString(fields.organizationId),
      module: readString(fields.module) as ActivityModule,
      eventType: readString(fields.eventType),
      title: readString(fields.title),
      summary: readString(fields.summary),
      priority: readNumber(fields.priority),
      metric: readOptionalString(fields.metric),
      actionLabel: readOptionalString(fields.actionLabel),
      actionUrl: readOptionalString(fields.actionUrl),
      personId: readOptionalString(fields.personId),
      createdAt: readOptionalString(fields.createdAt) ?? record.createdTime,
      metadata: readMetadata(fields.metadata),
    },
    record.id
  );
}

function toAirtableFields(event: ActivityEvent): Record<string, unknown> {
  return {
    organizationId: event.organizationId,
    module: event.module,
    eventType: event.eventType,
    priority: event.priority,
    title: event.title,
    summary: event.summary,
    metric: event.metric,
    actionLabel: event.actionLabel,
    actionUrl: event.actionUrl,
    personId: event.personId,
    createdAt: event.createdAt,
    metadata: JSON.stringify(event.metadata),
  };
}

function clampScore(value: number): number {
  if (!Number.isFinite(value)) return 0;
  return Math.max(0, Math.min(100, Math.round(value)));
}

function escapeFormulaValue(value: string): string {
  return value.replace(/'/g, "\\'");
}

function readString(value: unknown): string {
  return typeof value === "string" ? value : "";
}

function readOptionalString(value: unknown): string | undefined {
  return typeof value === "string" && value.length > 0 ? value : undefined;
}

function readNumber(value: unknown): number | undefined {
  return typeof value === "number" ? value : undefined;
}

function readMetadata(value: unknown): Record<string, unknown> {
  if (!value) return {};
  if (typeof value === "object" && !Array.isArray(value)) return value as Record<string, unknown>;
  if (typeof value !== "string") return {};

  try {
    const parsed = JSON.parse(value) as unknown;
    return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed as Record<string, unknown> : {};
  } catch {
    return {};
  }
}
