import type { ActivityEvent } from "./activity-events";

export interface BriefRequest {
  organizationId: string;
  userId?: string;
  role?: string;
  module?: string;
  time?: string | Date;
  userName?: string;
}

export interface BriefCard {
  id: string;
  title: string;
  summary: string;
  metric: string;
  actionLabel: string;
  actionUrl?: string;
  module: string;
  eventType: string;
  priority: number;
  score: number;
  personId?: string;
  createdAt: string;
  metadata: Record<string, unknown>;
}

export interface BriefResponse {
  greeting: string;
  topPriority?: BriefCard;
  todaysActivity: BriefCard[];
  recommendedActions: BriefCard[];
  recentEvents: BriefCard[];
  quickActions: BriefAction[];
  cards: BriefCard[];
}

export interface BriefAction {
  label: string;
  href: string;
  module?: string;
}

const EVENT_IMPORTANCE: Record<string, number> = {
  "parent connected": 20,
  "guide downloaded": 40,
  "guide opened": 40,
  "portal opened": 45,
  "opportunity captured": 55,
  "application started": 75,
  "course completed": 80,
  "newsletter sent": 80,
  "volunteer overdue": 90,
  "application approved": 95,
  "application completed": 95,
  "missed follow-up": 100,
};

export function buildBriefResponse(
  events: ActivityEvent[],
  request: BriefRequest,
  quickActions: BriefAction[] = []
): BriefResponse {
  const now = request.time ? new Date(request.time) : new Date();
  const cards = selectBriefCards(events, request, 5);
  const todaysActivity = events
    .filter((event) => isSameDay(new Date(event.createdAt), now))
    .map((event) => toBriefCard(event, request, now))
    .slice(0, 5);
  const recentEvents = [...events]
    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    .slice(0, 5)
    .map((event) => toBriefCard(event, request, now));

  return {
    greeting: buildGreeting(request.userName, now),
    topPriority: cards[0],
    todaysActivity,
    recommendedActions: cards.filter((card) => card.actionLabel).slice(0, 3),
    recentEvents,
    quickActions,
    cards,
  };
}

export function selectBriefCards(
  events: ActivityEvent[],
  request: BriefRequest,
  limit = 5
): BriefCard[] {
  const now = request.time ? new Date(request.time) : new Date();

  return events
    .filter((event) => event.organizationId === request.organizationId)
    .filter((event) => !request.module || event.module === request.module)
    .map((event) => toBriefCard(event, request, now))
    .sort((a, b) => b.score - a.score || new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    .slice(0, limit);
}

export function scoreActivityEvent(event: ActivityEvent, request: BriefRequest = { organizationId: event.organizationId }): number {
  const now = request.time ? new Date(request.time) : new Date();
  const eventAgeHours = Math.max(0, (now.getTime() - new Date(event.createdAt).getTime()) / 36e5);
  const recency = Math.max(0, 25 - eventAgeHours);
  const eventImportance = EVENT_IMPORTANCE[event.eventType.toLowerCase()] ?? 0;
  const dueDateBoost = getDueDateBoost(event.metadata, now);
  const riskBoost = readScore(event.metadata.risk);
  const engagementBoost = readScore(event.metadata.engagement);
  const aiImportance = readScore(event.metadata.aiImportance);

  return clampScore(event.priority * 0.35 + eventImportance * 0.25 + recency + dueDateBoost + riskBoost * 0.1 + engagementBoost * 0.1 + aiImportance * 0.2);
}

export function toBriefCard(event: ActivityEvent, request: BriefRequest, now = new Date()): BriefCard {
  const fallbackMetric = event.priority > 0 ? `Priority ${event.priority}` : event.eventType;

  return {
    id: event.id,
    title: event.title,
    summary: event.summary,
    metric: event.metric ?? fallbackMetric,
    actionLabel: event.actionLabel ?? "Review",
    actionUrl: event.actionUrl,
    module: event.module,
    eventType: event.eventType,
    priority: event.priority,
    score: scoreActivityEvent(event, { ...request, time: now }),
    personId: event.personId,
    createdAt: event.createdAt,
    metadata: event.metadata,
  };
}

function buildGreeting(userName: string | undefined, now: Date): string {
  const hour = now.getHours();
  const dayPart = hour < 12 ? "Good Morning" : hour < 17 ? "Good Afternoon" : "Good Evening";
  return userName ? `${dayPart}, ${userName}` : dayPart;
}

function getDueDateBoost(metadata: Record<string, unknown>, now: Date): number {
  const dueDate = typeof metadata.dueDate === "string" ? new Date(metadata.dueDate) : undefined;
  if (!dueDate || Number.isNaN(dueDate.getTime())) return 0;

  const daysUntilDue = (dueDate.getTime() - now.getTime()) / 864e5;
  if (daysUntilDue < 0) return 25;
  if (daysUntilDue <= 1) return 20;
  if (daysUntilDue <= 3) return 12;
  return 0;
}

function readScore(value: unknown): number {
  return typeof value === "number" && Number.isFinite(value) ? Math.max(0, Math.min(100, value)) : 0;
}

function clampScore(value: number): number {
  return Math.max(0, Math.min(100, Math.round(value)));
}

function isSameDay(a: Date, b: Date): boolean {
  return a.getFullYear() === b.getFullYear() && a.getMonth() === b.getMonth() && a.getDate() === b.getDate();
}
